function numberOfGoodSubsets(nums) {
    const MOD = 1e9 + 7;

    function isPrime(n) {
        if (n <= 1) return false;
        for (let i = 2; i ** 2 <= n; i++) {
            if (n % i === 0) return false;
        }
        return true;
    }

    const primes = [];
    for (let i = 2; i <= 90; i++) {
        if (isPrime(i)) primes.push(i);
    }

    const cnt = Array(100).fill(0);
    nums.forEach(n => cnt[n]++);

    const dp = Array(1 << 20).fill(0);
    dp[0] = 1;

    for (let i = 30; i > 0; i--) {
        if (cnt[i] === 0) continue;
        const mask = [];
        primes.forEach(j => {
            if (i % j === 0) {
                mask.push(j);
                while (i % j === 0) i /= j;
            }
        });
        if (i > 1) continue;

        let m = 0;
        mask.forEach(j => m |= 1 << (j - 2));

        for (let j = dp.length - 1; j >= 0; j--) {
            if (dp[j] === 0) continue;
            let cur = 1;
            for (let k = 0; k < cnt[m]; k++) {
                cur = (cur * 2) % MOD;
                dp[j | m] = (dp[j | m] + dp[j] * cur) % MOD;
            }
        }
    }

    let ans = 0;
    dp.forEach(n => ans = (ans + n) % MOD);

    ans = (ans - dp[0] + MOD) % MOD;
    return (ans * (1 << (cnt[1] - 1))) % MOD;
}
```

    1. First, we create a list of prime numbers up to 90 using the isPrime function.
2. Then, we count the occurrence of each number in the provided 'nums' array and write it into the 'cnt' array.
3. Initialize a dp array of size 2^20, setting dp[0] to 1.
4. Iterate over the numbers from 30 to 1. Skip the ones with a count of 0.
5. Create a bitmask 'm' to store the prime factors of the number 'i' shifted by 1.
6. Iterate over the dp array from right to left. Skip the zeros.
7. Set 'cur' to 1 and multiply it by 2 for each 'cnt[m]', then update dp[j | m] according to the formula dp[j | m] = (dp[j | m] + dp[j] * cur) % MOD.
8. Calculate the answer as the sum of the dp array, then subtract the initial dp[0] value and add MOD to it, and finally multiply by (1 << (cnt[1] - 1)).
9. Return the answer modulo MOD.

