import java.util.ArrayList;
import java.util.List;
import java.util.Arrays;

public class Solution {
    final int MOD = 1000000007;

    boolean isPrime(int n) {
        if (n <= 1) return false;
        for (int i = 2; i * i <= n; i++) {
            if (n % i == 0) return false;
        }
        return true;
    }

    public int numberOfGoodSubsets(int[] nums) {
        List<Integer> primes = new ArrayList<>();
        for (int i = 2; i <= 90; i++) {
            if (isPrime(i)) primes.add(i);
        }

        int[] cnt = new int[100];
        Arrays.fill(cnt, 0);
        for (int n : nums) cnt[n]++;

        long[] dp = new long[1 << 20];
        dp[0] = 1;

        for (int i = 30; i > 0; i--) {
            if (cnt[i] == 0) continue;
            List<Integer> mask = new ArrayList<>();
            for (int j : primes) {
                if (i % j == 0) {
                    mask.add(j);
                    while (i % j == 0) i /= j;
                }
            }
            if (i > 1) continue;

            int m = 0;
            for (int j : mask) m |= 1 << (j - 2);

            for (int j = dp.length - 1; j >= 0; j--) {
                if (dp[j] == 0) continue;
                long cur = 1;
                for (int k = 0; k < cnt[m]; k++) {
                    cur = (cur * 2) % MOD;
                    dp[j | m] = (dp[j | m] + dp[j] * cur) % MOD;
                }
            }
        }

        long ans = 0;
        for (long n : dp) ans = (ans + n) % MOD;

        ans = (ans - dp[0] + MOD) % MOD;
        return (int) ((ans * (1L << (cnt[1] - 1))) % MOD);
    }
}
```

